package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testPrintAndQuote() throws IOException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        CSVFormat spyFormat = spy(csvFormat);
        Object object = "test";
        CharSequence value = "value";
        int offset = 0;
        int len = value.length();
        Appendable out = new StringWriter();
        boolean newRecord = true;

        // When
        spyFormat.printAndQuote(object, value, offset, len, out, newRecord);

        // Then
        assertEquals("\"value\"", out.toString());
    }
}
